    return scs.binom(N, k) * pow(p,k) * pow(1.-p, N-k)

def gt_homo_gtmode(char[:] o, char[:] n,
                   double[:] a, double[:] b, 
                   double F, double tau, long n_snps, double[:] res):
    cdef int i
    for i in range(n_snps):
        res[i] = _gt_homo_gtmode_single(o=o[i], n=n[i], a=a[i], b=b[i], F=F, tau=tau)


def gt_homo_dist(double[:] a, double[:] b, double F, double tau, long n_snps, double[:, :] res):
    _gt_homo_dist_tau(a, b, F, tau, n_snps, res)
cdef void _gt_homo_dist(double[:] a, double[:] b, double F, long n_snps, double[:, :] res):
    cdef long i, g
    for i in range(n_snps):
        res[i, 0] =  (b[i]*b[i] + b[i] + a[i]*b[i]*F) / (a[i] + b[i]) / (a[i] + b[i] + 1)
        res[i, 2] =  (a[i]*a[i] + a[i] + a[i]*b[i]*F) / (a[i] + b[i]) / (a[i] + b[i] + 1)
        res[i, 1] =  (2.*a[i]*b[i]*(1-F)) / (a[i] + b[i]) / (a[i] + b[i] + 1)

cdef void _gt_homo_dist_tau(double[:] a, double[:] b, double F, double tau, long n_snps, double[:, :] res):
    cdef long i, g
    for i in range(n_snps):
        res[i, 0] =  (b[i]*b[i]*tau + b[i] + a[i]*b[i]*F * tau) / (a[i] + b[i]) / (tau *a[i] + tau *b[i] + 1)
        res[i, 2] =  (a[i]*a[i]*tau + a[i] + a[i]*b[i]*F * tau) / (a[i] + b[i]) / (tau *a[i] + tau *b[i] + 1)
        res[i, 1] =  1 - res[i, 0] - res[i, 2] #(2.*a[i]*b[i]*(1-F) * (1-tau)) / (a[i] + b[i]) / (a[i] + b[i] + 1)

cdef double _gt_homo_gtmode_single(char o, char n, double a, double b, double F, double tau):
    if n == 0:
        return 1
    if n == 1:
        return (a * o + b * (1-o)) / (a + b)
    if n == 2:
        if o == 0:
            return  (b*b*tau + b + a*b*F * tau) / (a + b) / (tau *a + tau *b + 1)
        elif o == 2:
            return (a*a*tau + a + a*b*F * tau) / (a + b) / (tau *a + tau *b + 1) 
        elif o == 1:
            return (a*b*(1-F) * tau) / (a + b) / (tau *a + tau *b + 1) 
    return -1

def cpu(mem, input_buf):
    cdef int ADD = 1
    cdef int MUL = 2
    cdef int INPUT = 3
    cdef int OUTPUT = 4
    cdef int JIT = 5
    cdef int JIF = 6
    cdef int LESS = 7
    cdef int EQ = 8
    cdef int QUIT = 99

    cdef int MODE_POS = 0  # position mode
    cdef int MODE_IMM = 1  # immediate mode

    cdef int DEBUG = 0

    cdef int param_types[4]

    def debug(*args):
        if DEBUG:
            print(*args)

    cdef int ip = 0
    while 1:
        params_and_op = str(mem[ip])

        params = list(int(p) for p in params_and_op[:-2].rjust(3, "0"))
        params.reverse()

        op = int(params_and_op[-2:])
        if op == QUIT:
            break

        if op == ADD:
            a, b, out = mem[ip + 1 : ip + 4]
            ip += 4
            if params[0] == MODE_POS:
                a = mem[a]
            if params[1] == MODE_POS:
                b = mem[b]
            mem[out] = a + b
            debug(params_and_op, "ADD", a, b, out, mem[out])
        elif op == MUL:
            a, b, out = mem[ip + 1 : ip + 4]
            ip += 4
            if params[0] == MODE_POS:
                a = mem[a]
            if params[1] == MODE_POS:
                b = mem[b]
            mem[out] = a * b
            debug(params_and_op, "MUL", a, b, out, mem[out])
        elif op == INPUT:
            loc = mem[ip + 1]
            ip += 2
            if params[0] == MODE_IMM:
                raise Exception(f"Unexpected immediate mode input {params_and_op}")
            mem[loc] = int(input_buf.pop(0))
            debug(params_and_op, "INPUT", loc, mem[loc])
        elif op == OUTPUT:
            loc = mem[ip + 1]
            ip += 2
            if params[0] == MODE_POS:
                loc = mem[loc]
            print(loc)
        elif op == JIT:
            test, val = mem[ip + 1 : ip + 3]
            ip += 3
            if params[0] == MODE_POS:
                test = mem[test]
            if params[1] == MODE_POS:
                val = mem[val]
            if test:
                ip = val
            debug(params_and_op, "JIT", test, val, ip)
        elif op == JIF:
            test, val = mem[ip + 1 : ip + 3]
            ip += 3
            if params[0] == MODE_POS:
                test = mem[test]
            if params[1] == MODE_POS:
                val = mem[val]
            if not test:
                ip = val
            debug(params_and_op, "JIF", test, val, ip)
        elif op == LESS:
            a, b, out = mem[ip + 1 : ip + 4]
            ip += 4
            if params[0] == MODE_POS:
                a = mem[a]
            if params[1] == MODE_POS:
                b = mem[b]
            mem[out] = 1 if a < b else 0
            debug(params_and_op, "LESS", a, b, out, mem[out])
        elif op == EQ:
            a, b, out = mem[ip + 1 : ip + 4]
            ip += 4
            if params[0] == MODE_POS:
                a = mem[a]
            if params[1] == MODE_POS:
                b = mem[b]
            mem[out] = 1 if a == b else 0
            debug(params_and_op, "EQ", a, b, out, mem[out])
        else:
            raise Exception(f"Invalid op: {op}")
